// ============================================================================
// GREEDY MIDDLE-OUT CONTEXT EXTRACTION ALGORITHM
// ============================================================================
// 
// PURPOSE:
// When workflows fail, we need to send context to an AI for analysis.
// However, full workflow/execution dumps can be massive (100K+ chars),
// exceeding LLM context windows and wasting tokens on irrelevant data.
//
// STRATEGY:
// Instead of dumping everything, we use a "middle-out" approach:
// 1. Start at the FAILED NODE (the epicenter of the error)
// 2. Expand outward in "hops" - first direct connections, then their connections
// 3. For each node, include: definition, parameters, input data, output data
// 4. Stop when we hit our character budget (default 50K chars)
// 5. NEVER truncate mid-node - either include a full node or skip it
//
// WHY THIS WORKS:
// - The failed node and its immediate neighbors contain 90% of relevant context
// - Distant nodes are rarely relevant to the root cause
// - This gives AI the "smoking gun" without drowning it in noise
// - We respect token limits while maximizing signal-to-noise ratio
//
// ============================================================================

const MAX_CONTEXT_CHARS = 50000; // Configurable budget - adjust based on your LLM

// Get input data from previous node
const inputData = $input.item.json;
const failedNode = inputData.failed_node;

// Parse workflow and execution JSON from error trigger
let workflowData, executionData;
try {
  workflowData = inputData.workflow || {};
  executionData = inputData.execution || {};
} catch (e) {
  // Fallback if parsing fails
  return {
    ...inputData,
    workflow_json: JSON.stringify({ error: 'Failed to parse workflow data' }),
    execution_json: JSON.stringify({ error: 'Failed to parse execution data' })
  };
}

// ============================================================================
// STEP 1: BUILD NODE CONNECTION GRAPH
// ============================================================================
// We need to know which nodes connect to which, so we can expand outward

const nodeConnections = new Map(); // node_name -> Set of connected node names
const nodeDefinitions = new Map(); // node_name -> node definition

// Parse workflow nodes
if (workflowData.nodes) {
  workflowData.nodes.forEach(node => {
    nodeDefinitions.set(node.name, node);
    nodeConnections.set(node.name, new Set());
  });
}

// Parse connections to build adjacency graph
if (workflowData.connections) {
  Object.keys(workflowData.connections).forEach(sourceNode => {
    const connections = workflowData.connections[sourceNode];
    if (connections.main) {
      connections.main.forEach(outputConnections => {
        if (outputConnections) {
          outputConnections.forEach(conn => {
            // Add bidirectional edges (we want to traverse both ways)
            nodeConnections.get(sourceNode)?.add(conn.node);
            nodeConnections.get(conn.node)?.add(sourceNode);
          });
        }
      });
    }
  });
}

// ============================================================================
// STEP 2: EXTRACT EXECUTION DATA FOR EACH NODE
// ============================================================================
// Get the actual input/output data from the execution

const nodeExecutionData = new Map(); // node_name -> execution data

if (executionData.data && executionData.data.resultData) {
  const runData = executionData.data.resultData.runData || {};
  Object.keys(runData).forEach(nodeName => {
    nodeExecutionData.set(nodeName, runData[nodeName]);
  });
}

// ============================================================================
// STEP 3: GREEDY MIDDLE-OUT EXPANSION
// ============================================================================
// Start from failed node, expand outward hop by hop until budget exhausted

const includedNodes = new Set();
const nodesToProcess = [failedNode]; // Queue for BFS traversal
const processedNodes = new Set();
let currentHop = 0;
let totalChars = 0;

// Helper function to estimate size of a node's context
function estimateNodeSize(nodeName) {
  let size = 0;

  // Node definition size
  const nodeDef = nodeDefinitions.get(nodeName);
  if (nodeDef) {
    size += JSON.stringify(nodeDef).length;
  }

  // Execution data size
  const execData = nodeExecutionData.get(nodeName);
  if (execData) {
    size += JSON.stringify(execData).length;
  }

  return size;
}

// BFS traversal with budget constraint
while (nodesToProcess.length > 0 && currentHop < 10) { // Max 10 hops as safety
  const currentLevelSize = nodesToProcess.length;
  const nextLevel = [];

  // Process all nodes at current hop level
  for (let i = 0; i < currentLevelSize; i++) {
    const nodeName = nodesToProcess.shift();

    if (processedNodes.has(nodeName)) continue;
    processedNodes.add(nodeName);

    // Check if adding this node would exceed budget
    const nodeSize = estimateNodeSize(nodeName);

    if (totalChars + nodeSize <= MAX_CONTEXT_CHARS) {
      // We have budget - include this node
      includedNodes.add(nodeName);
      totalChars += nodeSize;

      // Add neighbors to next level
      const neighbors = nodeConnections.get(nodeName) || new Set();
      neighbors.forEach(neighbor => {
        if (!processedNodes.has(neighbor)) {
          nextLevel.push(neighbor);
        }
      });
    } else {
      // Budget exhausted - stop expansion
      break;
    }
  }

  // Move to next hop level
  nodesToProcess.push(...nextLevel);
  currentHop++;

  // If we couldn't add any nodes this level, stop
  if (nextLevel.length === 0) break;
}

// ============================================================================
// STEP 4: BUILD FILTERED WORKFLOW AND EXECUTION JSON
// ============================================================================
// Only include nodes that made it into our budget

// Filter workflow nodes
const filteredNodes = [];
includedNodes.forEach(nodeName => {
  const nodeDef = nodeDefinitions.get(nodeName);
  if (nodeDef) {
    filteredNodes.push(nodeDef);
  }
});

// Filter workflow connections
const filteredConnections = {};
if (workflowData.connections) {
  Object.keys(workflowData.connections).forEach(sourceNode => {
    if (includedNodes.has(sourceNode)) {
      const connections = workflowData.connections[sourceNode];
      const filteredNodeConnections = { main: [] };

      if (connections.main) {
        connections.main.forEach(outputConnections => {
          if (outputConnections) {
            const filtered = outputConnections.filter(conn => 
              includedNodes.has(conn.node)
            );
            filteredNodeConnections.main.push(filtered.length > 0 ? filtered : null);
          } else {
            filteredNodeConnections.main.push(null);
          }
        });
      }

      if (filteredNodeConnections.main.some(c => c && c.length > 0)) {
        filteredConnections[sourceNode] = filteredNodeConnections;
      }
    }
  });
}

// Build filtered workflow JSON
const filteredWorkflow = {
  ...workflowData,
  nodes: filteredNodes,
  connections: filteredConnections,
  _context_metadata: {
    extraction_method: 'middle-out',
    failed_node: failedNode,
    hops_included: currentHop,
    nodes_included: includedNodes.size,
    total_nodes: nodeDefinitions.size,
    estimated_chars: totalChars,
    budget_chars: MAX_CONTEXT_CHARS
  }
};

// Filter execution data
const filteredRunData = {};
includedNodes.forEach(nodeName => {
  const execData = nodeExecutionData.get(nodeName);
  if (execData) {
    filteredRunData[nodeName] = execData;
  }
});

const filteredExecution = {
  ...executionData,
  data: {
    ...executionData.data,
    resultData: {
      ...executionData.data?.resultData,
      runData: filteredRunData
    }
  },
  _context_metadata: {
    extraction_method: 'middle-out',
    nodes_included: includedNodes.size
  }
};

// ============================================================================
// STEP 5: RETURN RESULTS
// ============================================================================
// Return all input fields plus our extracted context

return {
  ...inputData,
  workflow_json: JSON.stringify(filteredWorkflow, null, 2),
  execution_json: JSON.stringify(filteredExecution, null, 2),
  _extraction_stats: {
    nodes_included: Array.from(includedNodes),
    hops_traversed: currentHop,
    total_chars: totalChars,
    budget_chars: MAX_CONTEXT_CHARS,
    compression_ratio: (totalChars / (JSON.stringify(workflowData).length + JSON.stringify(executionData).length)).toFixed(2)
  }
};
